import React from 'react'
import logo120 from './logo/Logo 804444 120.png'

const NavBar = () => {
  return (
    <>  
      <nav className="navbar">
        <a className="navbar-brand" href=""><img src={logo120} alt=""/></a>

        
        
        <a class="nav-link active my-2 my-sm-0" href="#">Portfolio</a>
       
          
      </nav>   
    </>
  )
}

export default NavBar
